import{_ as i,o as a,c as t,e as r}from"./app-641f5373.js";const c={},e=r('<h2 id="什么是-javascript" tabindex="-1"><a class="header-anchor" href="#什么是-javascript" aria-hidden="true">#</a> 什么是 JavaScript</h2><div class="custom-container tip"><p class="custom-container-title">小结</p><p><strong>1. JavaScript 由哪三部分组成？</strong></p><ul><li>ECMAScript：ECMAScript 是 JavaScript 的核心规范，定义了语法、类型、语句、关键字、保留字、操作符、全局对象</li><li>DOM：提供与网页内容交互的方法和接口，它将网页表示为一个由节点组成的树状结构</li><li>BOM：提供与浏览器交互的方法和接口</li></ul><p><strong>2. JavaScript 和 ECMAScript 有什么关系？</strong></p><p>ECMAScript 是 JavaScript 的标准化规范，JavaScript 是 ECMAScript 的一个实现</p></div><h3 id="历史" tabindex="-1"><a class="header-anchor" href="#历史" aria-hidden="true">#</a> 历史</h3><ul><li>1995 年问世（网景与 Sun 公司开发），目的是让客户端处理输入验证</li><li>1997 年，为解决像 Netscape Navigator(JavaScript) 和 IE(JScript) 中存在多个版本 JavaScript 的问题，JavaScript1.1 作为提案被提交给欧洲计算机制造商协会 Ecma，由 TC39 打造出 ECMA-262，也就是 ECMAScript 脚本语言标准</li><li>1998 年，国际标准化组织 ISO 和国际电工委员会 IEC 也将 ECMAScript 采纳为标准，自此各家浏览器均以 ECMAScript 作为 JavaScript 实现的依据，但具体实现各有不同</li></ul><h3 id="javascript-实现" tabindex="-1"><a class="header-anchor" href="#javascript-实现" aria-hidden="true">#</a> JavaScript 实现</h3><p>JavaScript 不限于 ECMA-262 所定义的那样，它包含以下几个部分：</p><ul><li>核心（ECMAScript）：由 ECMA-262 定义并提供核心功能</li><li>文档对象模型（DOM）：提供与网页内容交互的方法和接口</li><li>浏览器对象模型（BOM）：提供与浏览器交互的方法和接口</li></ul><h4 id="ecmascript" tabindex="-1"><a class="header-anchor" href="#ecmascript" aria-hidden="true">#</a> ECMAScript</h4><p>ECMA-262 定义了什么？</p><ul><li>语法</li><li>类型</li><li>语句</li><li>关键字</li><li>保留字</li><li>操作符</li><li>全局对象</li></ul><p>ECMAScript 是实现 ECMA-262 这个规范描述的所有方面的一门语言，JavaScript 和 Adobe ActionScript 都实现了 ECMAScript</p><blockquote><p>Web 浏览器是 ECMAScript 的一种宿主环境，宿主环境提供 ECMAScript 的基准实现和与环境自身交互必需的扩展，扩展（如 DOM）使用 ECMAScript 的核心类型和语法提供特定于环境的额外功能</p></blockquote><h4 id="dom" tabindex="-1"><a class="header-anchor" href="#dom" aria-hidden="true">#</a> DOM</h4><p>文档对象模型（Document Object Model）是一个应用编程接口（API），DOM 通过创建表示文档的树，让开发者可以控制网页的结构和内容，使用 DOM API 可以轻松删除、添加、替换、修改节点</p><h4 id="bom" tabindex="-1"><a class="header-anchor" href="#bom" aria-hidden="true">#</a> BOM</h4><p>浏览器对象模型 BOM，用于支持访问和操作浏览器的窗口</p>',16),p=[e];function l(d,o){return a(),t("div",null,p)}const n=i(c,[["render",l],["__file","01.html.vue"]]);export{n as default};
